import React, { useEffect, useState } from "react";
import { api } from "../api";

export default function Dashboard({ onError }) {
  const [items, setItems] = useState([]);
  const [name, setName] = useState("");
  const [category, setCategory] = useState("Other");
  const [quantity, setQuantity] = useState(1);
  const [unit, setUnit] = useState("pcs");
  const [price, setPrice] = useState(0);
  const [expiry_date, setExpiry] = useState("");

  const [voiceText, setVoiceText] = useState("");
  const [barcode, setBarcode] = useState("");
  const [ocrFile, setOcrFile] = useState(null);
  const [ocrItems, setOcrItems] = useState([]);

  async function load() {
    try {
      const data = await api.listInventory();
      setItems(data);
    } catch (e) {
      onError(e.message);
    }
  }

  useEffect(() => { load(); }, []);

  async function addManual() {
    try {
      await api.addItem({
        name, category, quantity: Number(quantity), unit,
        price: Number(price),
        expiry_date: expiry_date ? expiry_date : null
      });
      setName(""); setPrice(0); setQuantity(1); setExpiry("");
      load();
    } catch (e) {
      onError(e.message);
    }
  }

  async function del(id) {
    try { await api.deleteItem(id); load(); }
    catch (e) { onError(e.message); }
  }

  async function doQuickAdd() {
    try {
      await api.quickAdd(voiceText);
      setVoiceText("");
      load();
    } catch (e) {
      onError(e.message);
    }
  }

  async function doBarcodeLookup() {
    try {
      const info = await api.barcodeLookup(barcode);
      setName(info.name);
      setCategory(info.category);
      setExpiry(info.estimated_expiry_date);
    } catch (e) {
      onError(e.message);
    }
  }

  async function doOCR() {
    try {
      if (!ocrFile) return;
      const res = await api.ocrReceipt(ocrFile);
      setOcrItems(res.items || []);
    } catch (e) {
      onError(e.message);
    }
  }

  async function commitOCR() {
    try {
      if (!ocrItems.length) return;
      await api.ocrCommit(ocrItems);
      setOcrItems([]);
      setOcrFile(null);
      load();
    } catch (e) {
      onError(e.message);
    }
  }

  return (
    <div>
      <div className="card">
        <h2>Pantry Dashboard</h2>
        <p className="small">At-Risk = expiry within 48 hours</p>

        <h3>Add Item (Manual / Barcode)</h3>
        <div className="row">
          <div>
            <label>Name</label>
            <input value={name} onChange={(e)=>setName(e.target.value)} />
          </div>
          <div>
            <label>Category</label>
            <input value={category} onChange={(e)=>setCategory(e.target.value)} />
          </div>
        </div>

        <div className="row">
          <div>
            <label>Quantity</label>
            <input type="number" value={quantity} onChange={(e)=>setQuantity(e.target.value)} />
          </div>
          <div>
            <label>Unit</label>
            <input value={unit} onChange={(e)=>setUnit(e.target.value)} />
          </div>
          <div>
            <label>Price</label>
            <input type="number" value={price} onChange={(e)=>setPrice(e.target.value)} />
          </div>
          <div>
            <label>Expiry Date</label>
            <input type="date" value={expiry_date} onChange={(e)=>setExpiry(e.target.value)} />
          </div>
        </div>

        <button className="primary" onClick={addManual}>Add</button>

        <h3 style={{marginTop:16}}>Barcode Lookup (auto-fill)</h3>
        <div className="row">
          <div>
            <label>Barcode</label>
            <input value={barcode} onChange={(e)=>setBarcode(e.target.value)} />
          </div>
          <div style={{display:"flex", alignItems:"end"}}>
            <button className="primary" onClick={doBarcodeLookup}>Lookup</button>
          </div>
        </div>

        <h3 style={{marginTop:16}}>Voice / NLP Quick Add</h3>
        <div className="row">
          <div>
            <label>Text (example: "add 2 liters of milk")</label>
            <input value={voiceText} onChange={(e)=>setVoiceText(e.target.value)} />
          </div>
          <div style={{display:"flex", alignItems:"end"}}>
            <button className="primary" onClick={doQuickAdd}>Quick Add</button>
          </div>
        </div>

        <h3 style={{marginTop:16}}>Receipt OCR</h3>
        <input type="file" accept="image/*" onChange={(e)=>setOcrFile(e.target.files?.[0] || null)} />
        <div style={{marginTop:10}}>
          <button className="primary" onClick={doOCR}>Run OCR</button>
          <button style={{marginLeft:10}} onClick={commitOCR}>Save OCR Items</button>
        </div>

        {ocrItems.length > 0 && (
          <div style={{marginTop:10}}>
            <h4>OCR Items</h4>
            <ul>
              {ocrItems.map((it, idx)=>(
                <li key={idx}>{it.name} — {it.quantity} {it.unit} — ₹{it.price}</li>
              ))}
            </ul>
          </div>
        )}
      </div>

      <div className="card">
        <h3>Inventory</h3>
        <table className="table">
          <thead>
            <tr>
              <th>Item</th><th>Qty</th><th>Expiry</th><th>Status</th><th></th>
            </tr>
          </thead>
          <tbody>
            {items.map(it => (
              <tr key={it.id}>
                <td>{it.name} <span className="badge">{it.category}</span></td>
                <td>{it.quantity} {it.unit}</td>
                <td>{it.expiry_date || "-"}</td>
                <td>
                  {it.expiry_date
                    ? (it.at_risk ? <span className="badge danger">At Risk</span> : <span className="badge risk">{it.days_to_expiry} days</span>)
                    : <span className="badge">No expiry</span>
                  }
                </td>
                <td><button className="danger" onClick={()=>del(it.id)}>Delete</button></td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}
